mapper.select:
SELECT ol.*, COALESCE(t.teacher_name, s.student_name) AS operate_user_name FROM operate_log ol LEFT JOIN teacher t ON ol.operate_user_id = t.teacher_id LEFT JOIN student s ON ol.operate_user_id = s.student_id WHERE 1=1
AND (ol.operate_content LIKE CONCAT('%',#{keyword},'%') OR COALESCE(t.teacher_name, s.student_name) LIKE CONCAT('%',#{keyword},'%'))
AND ol.operate_type=#{operateType}
ORDER BY ol.operate_time DESC LIMIT #{offset},#{size}

SELECT COUNT(*) FROM operate_log WHERE 1=1

    AND (operate_content LIKE CONCAT('%',#{keyword},'%'))


    AND operate_type=#{operateType}
